import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AnonymousSubject } from 'rxjs/internal/Subject';
import { ArticleService } from 'src/app/services/article.service';
import { CartService } from 'src/app/services/cart.service';
import { ClientService } from 'src/app/services/client.service';
import { GuestService } from 'src/app/services/guest.service';

@Component({
  selector: 'app-account-client',
  templateUrl: './account-client.component.html',
  styleUrls: ['./account-client.component.css']
})
export class AccountClientComponent {
  loggedIn = JSON.parse(localStorage.getItem("loggedIn")!)
  userconnect = JSON.parse(localStorage.getItem("Client")!)
  
  userconnectcontact = JSON.parse(localStorage.getItem("Contact")!)
  userconnectcomm = JSON.parse(localStorage.getItem("Commercial")!)
  role = JSON.parse(localStorage.getItem("role")!)
  formClient: FormGroup;
  cartItems: any[] = [];
  cartTotal: number = 0;
  commandes: any
  commandescontact : any
  commandesComm: any
  products: any
  clients: any
  guests: any[] = [];
  filterType: number | null = null;
  filterStatus: string | null = null;
  filterGuestName: string = '';
  constructor(private formBuilder: FormBuilder, private guestService: GuestService,private articleService: ArticleService, private clientService: ClientService, private router: Router, private cartService: CartService) {
    this.cartItems = this.cartService.cartItems;
    this.cartTotal = this.cartService.getTotal();

  }

  ngOnInit() {
    if (this.userconnectcomm) {
      this.getAllCommandeComm()

    }
    if (this.userconnect) {
      this.getAllCommande()

    }
    if (this.userconnectcontact) {
      this.getCommandeContact()
      this.loadGuests()
      this.getAllProductsCommande(159)

    }
    this.getClientsByComm()
    this.loadGuests();
    this.formClient = this.formBuilder.group({
      firstName: ['', Validators.required],
      lastName: ['', Validators.required],
      country: ['', Validators.required],
      companyName: ['', Validators.required],
      townCity: ['', Validators.required],
      postcode: ['', Validators.required],
      streetAddress: ['', Validators.required],
      phone: ['', Validators.required],
      email: ['', Validators.required],
      password: ['', Validators.required]
    })
    this.getPatchFormClient()
    this.getAllCommande()
  }
  getPatchFormClient() {
    this.formClient.patchValue({
      firstName: this.userconnect?.firstName,
      lastName: this.userconnect?.lastName,
      country: this.userconnect?.country,
      companyName: this.userconnect?.companyName,
      townCity: this.userconnect?.townCity,
      postcode: this.userconnect?.postcode,
      streetAddress: this.userconnect?.streetAddress,
      phone: this.userconnect?.phone,
      email: this.userconnect?.email,
      password: this.userconnect?.password
    })

  }
  loadGuests(): void {
    this.guestService.getGuests().subscribe(
      (data: any) => {
        this.guests = data;

      },
      (error) => {
        console.error('Erreur lors du chargement des invités', error);
      }
    );
  }


  getGuestName(GuestId: number): string {
    const guest = this.guests.find((g: any) => g.id === GuestId);
    return guest ? `${guest.nom} ${guest.prenom}` : 'Inconnu';
  }
  updateQuantity(product: any): void {
    this.cartService.updateQuantity(product, product?.quantity);
  }
  removeFromCart(item: any): void {
    this.cartService.removeFromCart(item);
    this.cartTotal = this.cartService.getTotal();
  }
  getTotalProduct(item: any): number {
    let total = 0;
    total += item.atfprix * item.quantity;
    return total;
  }
  clearCart(): void {
    this.cartService.clearCart();
    this.cartTotal = this.cartService.getTotal();
  }
  logout() {
    localStorage.clear()
    window.location.reload()
  }
getFilteredCommandes() {
  if (!this.commandescontact?.$values) return [];

  return this.commandescontact.$values.filter((commande: any) => {
    const matchType = !this.filterType || commande?.Type === this.filterType;
    const matchStatus = !this.filterStatus || commande?.Status === this.filterStatus;
    const matchGuest = !this.filterGuestName || 
      (this.getGuestName(commande?.GuestId)?.toLowerCase().includes(this.filterGuestName.toLowerCase()));

    return matchType && matchStatus && matchGuest;
  });
}

  
  getAllCommande() {
    this.articleService.getCommandeClient(this.userconnect?.tiers).subscribe(
      (res: any) => {
        this.commandes = res
        console.log("commande :" ,this.commandes)
      }
    )
    console.log("commandes :" , this.commandes);
  }
  getCommandeContact() {
    this.articleService.getCommandeContact(this.userconnectcontact?.tiers).subscribe(
      (res: any) => {
        this.commandescontact = res
        console.log("commandecsontact :" ,this.commandescontact)
      }
    )
    console.log("commandescontact :" , this.commandescontact);
  }

  getAllCommandeComm() {
    this.articleService.getCommandeCommercial(this.userconnectcomm?.tiers.trim()).subscribe(
      (res: any) => {
        this.commandesComm = res
      }
    )
  }
  getClientsByComm() {
    this.clientService.getClientByComm(this.userconnectcomm.tiers).subscribe(
      (res: any) => {
        this.clients = res
      })
  }
  getAllProductsCommande(id: any) {
    this.articleService.getAllArticleCommandes(id).subscribe(
      (res: any) => {
        this.products = res
        console.log("product :" ,this.products)

      }
      
    )
    console.log("product :" ,this.products)

  }
  downloadHTML(): void {
    // Construire le contenu du fichier HTML
    const htmlContent = this.generateHTML(this.products);
  
    // Créer un blob et un lien de téléchargement
    const blob = new Blob([htmlContent], { type: 'text/html;charset=utf-8;' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'produits.html';
    a.click();
    window.URL.revokeObjectURL(url);
  }
  
  private generateHTML(products: any[]): string {
 let html = `
  <html>
    <head>
      <title>Liste des Produits</title>
      <style>
        table {
          width: 100%;
          border-collapse: collapse;
          margin: 20px 0;
          font-size: 18px;
        }
        table, th, td {
          border: 1px solid black;
          padding: 10px;
          text-align: left;
        }
        th {
          background-color: #f2f2f2;
        }
        img.logo {
          display: block;
          margin: 20px auto;
          max-width: 200px;
          height: auto;
        }
      </style>
    </head>
    <body>
    <img src="data:image/png;base64," alt="Logo" class="logo" />
      <h1>Liste des Produits</h1>
      <table>
        <thead>
          <tr>
            <th>Produit</th>
            <th>Quantité</th>
            <th>Sref1</th>
            <th>Sref2</th>
            <th>Nombre de points de fidelite</th>
          </tr>
        </thead>
        <tbody>
`;

  
    let totalPrix = 0; 
    products.forEach(product => {
      html += `
        <tr>
          <td>${product.des}</td>
          <td>${product.quantite}</td>
          <td>${product.sref1}</td>
          <td>${product.sref2}</td>
          <td>${product.fidelity}</td>
        </tr>
      `;
    });
  
    // Ajouter le total des prix
    html += `
            </tbody>
          </table>
        </body>
      </html>
    `;
  
    return html;
  }
  
  
  
}
